targets.expr:
sum by(type) (
  label_replace(
    count_over_time({service_name="zigbee2mqtt", type=~".*_error", type!="route_error"} [$__interval]),
    "device", "$1", "device", "(.+)"
  )
)
or
sum by(type) (
  label_replace(
    count_over_time({service_name="zigbee2mqtt", type="route_error"} [$__interval]),
    "device", "$1", "friendly_name", "(.+)"
  )
)

sum by(device, type) (
  label_replace(
    count_over_time({service_name="zigbee2mqtt", type=~".*_error", type!="route_error"} [$__range]),
    "device", "$1", "device", "(.+)"
  )
)
or
sum by(device, type) (
  label_replace(
    count_over_time({service_name="zigbee2mqtt", type="route_error"} [$__range]),
    "device", "$1", "friendly_name", "(.+)"
  )
)

